<div class="fr">
<svg viewBox="0 0 700 420" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="32" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Deux Modèles de Régulation de la Tokenisation</text>
  <g font-family="sans-serif">
    <rect x="20" y="54" width="310" height="330" rx="10" fill="#14283f" stroke="#38bdf8" stroke-width="1.6"/>
    <text x="175" y="86" fill="#7dd3fc" text-anchor="middle" font-size="14" font-weight="800">MiCA de l'UE (en vigueur depuis 2024)</text>
    <text x="40" y="118" fill="#e4e4e7" font-size="13">Approche : règlement unique et contraignant</text>
    <text x="40" y="146" fill="#e4e4e7" font-size="13">Portée : s'applique aux 27 États membres</text>
    <text x="40" y="174" fill="#e4e4e7" font-size="13">Application : supervision directe de l'UE</text>
    <text x="40" y="202" fill="#e4e4e7" font-size="13">Vitesse : contraignant dès l'entrée en vigueur</text>
    <text x="40" y="242" fill="#7dd3fc" font-size="13" font-weight="700">Pour : prévisible, effet immédiat</text>
    <text x="40" y="266" fill="#a1a1aa" font-size="13">Contre : long consensus à 27,</text>
    <text x="40" y="290" fill="#a1a1aa" font-size="13">moins flexible</text>
    <rect x="356" y="54" width="324" height="330" rx="10" fill="#1f1710" stroke="#f7931a" stroke-width="1.6"/>
