<div class="pt">
<svg viewBox="0 0 700 420" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="32" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Dois Modelos de Regulação de Tokenização</text>
  <g font-family="sans-serif">
    <rect x="20" y="54" width="310" height="330" rx="10" fill="#14283f" stroke="#38bdf8" stroke-width="1.6"/>
    <text x="175" y="86" fill="#7dd3fc" text-anchor="middle" font-size="14" font-weight="800">MiCA da UE (em vigor desde 2024)</text>
    <text x="40" y="118" fill="#e4e4e7" font-size="13">Abordagem: regulamento único e vinculante</text>
    <text x="40" y="146" fill="#e4e4e7" font-size="13">Alcance: aplica-se a 27 Estados-membros</text>
    <text x="40" y="174" fill="#e4e4e7" font-size="13">Aplicação: supervisão direta da UE</text>
    <text x="40" y="202" fill="#e4e4e7" font-size="13">Velocidade: vinculante ao entrar em vigor</text>
